"""
MKT Context Layer — Proverbs chapters 28–30
Run: python3 scripts/zc-context-proverbs-28-30.py

Ch28: 28 verses — law-keeping / wisdom coalescence; poor/rich reversal; confession-mercy;
      city turbulence as social commentary; banking and usury (ANE loan practices)
Ch29: 27 verses — royal justice tradition; prophetic vision (chazon) as social ordering;
      discipline ideology (Mesopotamian pedagogical parallels); mockers / wise dynamic
Ch30: 33 verses — Agur ben Jakeh and Ithiel / Ucal; divine name question;
      numerical sayings (x/x+1 form); Lemuel's mother's instruction (31:1-9 context)
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

DATA = {
  "28": {
    "1": "<p>The <em>wicked flee when no one pursues</em> — the observation is psychological: guilt creates its own pursuit. ANE wisdom consistently linked inner moral disorder to outward fearfulness; Egyptian texts note that the guilty man lives as if enemies are always near. The contrast with the righteous who are <em>bold as a lion</em> (Prov 28:1) draws on the lion's status in ANE royal iconography as the fearless apex predator — courage here signals moral integrity rather than military prowess.</p>",
    "2": "<p><em>When a land transgresses, it has many rulers</em> — the political instability formula. Ancient Near Eastern political theory linked successive coups and short reigns directly to moral disorder in the land; the Mesopotamian King Lists show this pattern in the historical record. Conversely, a ruler of understanding (<em>mevin yodea</em>) prolongs stability — the sage-king ideal common to Egyptian and Israelite wisdom. The verse reflects the Deuteronomic covenant framework: national sin = national chaos.</p>",
    "3": "<p><em>A poor man who oppresses the poor is like a driving rain that leaves no food</em> — the violent rain metaphor describes rain so intense it destroys crops rather than nourishing them. The social observation is acute: oppression from within the poor community was a known reality in ancient subsistence economies where small landowners or minor officials could extract from those even more vulnerable. The Hebrew <em>rash</em> (poor) governs both roles, making the internal contradiction visible.</p>",
    "4": "<p><em>Those who forsake the law praise the wicked; those who keep the law strive against them</em> — <em>torah</em> here functions as the comprehensive standard of wisdom-order, not narrowly legal code. The social alignment observation: people tend to approve behavior that mirrors their own moral commitments. This is the wisdom tradition's version of moral sociology — character shapes perception and social alliance. Egyptian wisdom similarly noted that fools gather to fools and the wise to wise.</p>",
    "5": "<p><em>Evil men do not understand justice; those who seek the LORD understand it fully</em> — the epistemological claim: moral perception is conditioned by character. The term <em>mishpat</em> (justice) encompasses both legal and cosmic ordering — understanding it requires the inner orientation that comes from seeking the LORD. ANE wisdom traditions (Amenemope, Babylonian counsels) made analogous claims about the god-fearing man's superior perception, though without the monotheistic specificity of Proverbs.</p>",
    "6": "<p><em>Better a poor man who walks in his integrity than a rich man who is crooked in his ways</em> — the better-than proverb (<em>tov min</em> form) is a rhetorical device throughout ancient Near Eastern wisdom. The Egyptian <em>Instruction of Amenemope</em> makes identical value-inversions, preferring the poor-but-honest over the wealthy-but-corrupt (ch.6-7 of Amenemope). Proverbs 28:6 parallels 19:1 almost exactly, suggesting a traditional saying that circulated in multiple contexts.</p>",
    "7": "<p><em>The one who keeps the law is a son who makes a wise father glad</em> — the father-son frame that dominates Proverbs 1–9 recurs here. The connection between law-keeping and family honor is fundamental to ANE patriarchal social structures. The second half — <em>a companion of gluttons shames his father</em> — reflects the ANE concern for family reputation; in honor-shame cultures, a son's associations defined the father's social standing as much as his own conduct.</p>",
    "8": "<p><em>Whoever multiplies his wealth by interest and profit from the poor will gather it for him who is generous to the poor</em> — the Hebrew <em>neshekh</em> (interest, literally 'bite') and <em>tarbit</em> (increase) are the standard OT terms for usurious lending. ANE loan documents from Mesopotamia show interest rates of 20-33% on silver and 33% on grain — rates that could ruin smallholders in bad harvest years. The verse invokes the legal tradition prohibiting interest on loans to fellow Israelites (Exod 22:25; Lev 25:36-37) and predicts a providential reversal: the wealth extracted from the poor will eventually reach the generous.</p>",
    "9": "<p><em>If one turns away his ear from hearing the law, even his prayer is an abomination</em> — the cultic observation that ritual piety disconnected from ethical obedience is repugnant to God is a consistent thread from Moses through the prophets (Amos 5:21-24; Isa 1:15). Here it appears in the wisdom tradition's cooler register: the man who will not hear the instruction of wisdom finds that his religious observance becomes the very thing God rejects. The logical connection is character-based: the ear closed to instruction is the same ear that cannot approach the Holy One.</p>",
    "10": "<p><em>Whoever misleads the upright into an evil way will fall into his own pit, but the blameless will have a goodly inheritance</em> — the pit-trap imagery is common in ANE wisdom and psalms (cf. Ps 7:15; Prov 26:27). The trap-for-others-becomes-trap-for-self is a retribution formula appearing in Egyptian, Babylonian, and Israelite literature. The inheritance language (<em>nachalah</em>) at the verse's close ties the long-term reward to the land-gift tradition of the covenant.</p>",
    "11": "<p><em>A rich man is wise in his own eyes, but a poor man who has understanding will find him out</em> — the penetrating social observation: wealth creates the illusion of wisdom. In ANE court contexts, the wealthy patron's assessments carried disproportionate authority simply because of social position. The proverb punctures this: <em>mevin</em> (one who understands) can see through the pretension that wealth creates — a democratizing epistemology that attributes true insight to character rather than status.</p>",
    "12": "<p><em>When the righteous triumph, there is great glory; but when the wicked rise, people hide themselves</em> — the social-barometric function: the visibility of the righteous or wicked in public life measures civic health. ANE royal inscriptions regularly described the king's triumph as the restoration of order in which the population could live openly. Proverbs democratizes this: it is the character of the community's leaders and prominent members, not just the king, that sets the social climate.</p>",
    "13": "<p><em>Whoever conceals his transgressions will not prosper, but he who confesses and forsakes them will obtain mercy</em> — <em>mekhasse</em> (conceals) and <em>modeh</em> (confesses) frame the verse as a choice between two postures before God and community. ANE confession rituals are well documented in Mesopotamian penitential psalms (<em>ershahunga</em>), where the supplicant enumerates sins before the god and receives release. But Proverbs adds the verb <em>ve'azav</em> (forsakes) — confession alone is insufficient; the abandonment of the behavior is what secures mercy. This two-movement understanding (confession + behavioral change) has no precise ANE parallel.</p>",
    "14": "<p><em>Blessed is the one who fears the LORD always, but whoever hardens his heart will fall into calamity</em> — <em>qasheh lev</em> (hardened heart) is the condition Pharaoh exemplifies in the Exodus narratives and that Proverbs identifies as the antithesis of wisdom. The hardened heart is the closed heart — closed to instruction, to rebuke, to the fear of God. The beatitude form (<em>ashrei</em>) used here places this verse in the tradition of Psalm 1 and the wisdom-beatitudes of Proverbs 8.</p>",
    "15": "<p><em>Like a roaring lion or a charging bear is a wicked ruler over a poor people</em> — the predator-imagery applied to political oppression reflects ANE use of lion/bear symbolism for both royal power and its abuse. Reliefs from Assyria and Egypt depict kings hunting lions — the king both embodies and controls the predator. When the king becomes the predator against his own people, he inverts his divinely mandated role (cf. Ezek 34, where the shepherds are charged with eating rather than feeding the flock). The pairing lion/bear appears also in 1 Sam 17:34 (David vs. animals) and Dan 7:4-5 (world empires as beasts).</p>",
    "16": "<p><em>A ruler who lacks understanding is a cruel oppressor, but he who hates unjust gain will prolong his days</em> — the longevity formula tied to just governance is the standard of ANE royal ideology. Egyptian <em>Instruction for Merikare</em> and Mesopotamian royal wisdom texts consistently promise that just governance extends the king's reign. The specific vice identified — <em>maasei betzah</em> (gain by violence/extortion) — is the most commonly cited royal abuse in prophetic literature (Isa 56:11; Ezek 22:12; Mic 3:11).</p>",
    "17": "<p><em>If one is burdened with the blood of another, he will be a fugitive until death</em> — the bloodguilt principle: homicide creates a state of impurity that pursues the killer. This is the legal-theological basis for the cities of refuge (Num 35:11-34) — the accidental killer could flee there; the intentional killer had no refuge. The verse implies no legal escape: the killer (<em>osheq benefesh adam</em>, one who oppresses a human life) carries the burden permanently. ANE law codes (Hammurabi, Hittite laws) had similar provisions for bloodguilt, though with ransom possibilities that Israelite law excluded for murder.</p>",
    "18": "<p><em>Whoever walks in integrity will be delivered, but he who is crooked in his ways will suddenly fall</em> — the contrast between <em>holekh tamim</em> (one who walks in wholeness/integrity) and the one with double paths (<em>ne'qash derachayim</em>) uses the walking metaphor central to wisdom literature. The double-path image evokes one who presents different faces in different contexts — a form of deception that ultimately collapses under its own internal inconsistency. The sudden fall (<em>yippol beachath</em>) suggests not gradual decline but the catastrophic exposure of hidden duplicity.</p>",
    "19": "<p><em>Whoever works his land will have plenty of bread, but he who follows worthless pursuits will have plenty of poverty</em> — the agricultural-realism proverb: land rewards consistent labor. This verse parallels 12:11 almost verbatim, suggesting it was a traditional saying. The <em>reqim</em> (empty/worthless things) the fool pursues are never specified — the point is the pattern of misdirected energy rather than any particular vice. In ANE agricultural contexts, the subsistence margin was thin enough that laziness or distraction during critical planting/harvest windows could mean starvation — the proverb is not merely moralizing but observational.</p>",
    "20": "<p><em>A faithful man will abound with blessings, but whoever hastens to be rich will not go unpunished</em> — <em>ish emunot</em> (a man of faithfulnesses) — the plural suggests consistent, habitual trustworthiness across many situations. The haste-toward-wealth theme is a consistent wisdom critique (cf. Prov 20:21; 23:4-5); ANE wisdom texts (Amenemope ch.7-8) make the identical contrast between the measured, godly man and the one who rushes toward gain. The punishment formula (<em>lo yinnaqeh</em>, will not be held innocent) draws on legal vocabulary — there is a divine accounting behind the proverb's economics.</p>",
    "21": "<p><em>To show partiality is not good, yet for a piece of bread a man will do wrong</em> — <em>haker panim</em> (recognizing faces, i.e. favoritism) is condemned repeatedly in the legal tradition (Lev 19:15; Deut 1:17; 16:19). The second clause makes the observation ruthlessly concrete: the bribe needed to corrupt a judge need not be large. Egyptian wisdom (<em>Admonitions of Ipuwer</em>) and Mesopotamian wisdom texts both lament judicial corruption as a sign of social collapse. Proverbs here moves from prohibition to observation: the failure is less dramatic than usually imagined — just one meal's worth of inducement.</p>",
    "22": "<p><em>A stingy man hastens after wealth and does not know that poverty will come upon him</em> — <em>tov ayin</em> (good eye) in 22:9 = generosity; its opposite here, the <em>ra ayin</em> (evil eye), the stingy person, hastens after wealth by withholding from others. The irony: hoarding produces poverty, while generosity produces abundance — this is the paradox the wisdom tradition consistently articulates and which is grounded in the belief that God manages the economics of generosity. The evil-eye concept had wide ANE currency as a social harm; Proverbs co-opts it for the wisdom-economy argument.</p>",
    "23": "<p><em>Whoever rebukes a man will afterward find more favor than he who flatters with his tongue</em> — the rebuke-vs-flattery contrast is a recurring wisdom theme (Prov 27:5-6; 29:5). ANE court culture had powerful pressures toward flattery — advisors who told kings what they wished to hear outlasted those who offered honest counsel, at least in the short term. Proverbs consistently valorizes the honest rebuke over the pleasant lie, with the long-term social calculus favoring truth-tellers.</p>",
    "24": "<p><em>Whoever robs his father or his mother and says, 'That is no transgression,' is a companion to a man who destroys</em> — fifth commandment violation recast in wisdom terms. The declaration of innocence (<em>ein pasha</em>, no transgression) after the act is the self-deception that wisdom constantly exposes. In ANE family-economy contexts, parents' resources were often the primary source of informal credit and inheritance; robbing them was not merely a moral failing but a destruction of the family's economic foundation. The companion-to-destroyer (<em>ish mashchit</em>) identification is a social judgment: such a person belongs among those who wreck communities.</p>",
    "25": "<p><em>A greedy man stirs up strife, but the one who trusts in the LORD will be enriched</em> — <em>rechav nefesh</em> (wide of soul, greedy) vs. trust in the LORD: the contrast between self-oriented grasping and theocentric dependence. The strife-production of greed is sociologically observed: the person who must always take more than his share creates conflict at every interaction. The enrichment (<em>yedushan</em>, will be made fat) promised to the one who trusts uses the agricultural-abundance metaphor — prosperity as the fruit of a life oriented toward God rather than acquisition.</p>",
    "26": "<p><em>Whoever trusts in his own mind is a fool, but he who walks in wisdom will be delivered</em> — self-reliance in the form of exclusive trust in one's own heart/mind (<em>boteach belibo</em>) is the wisdom tradition's definition of folly. The Hebrew <em>lev</em> encompasses mind, will, and character together — trust in one's lev is not intellectual confidence but comprehensive self-sufficiency. ANE wisdom texts consistently emphasize dependence on the god's guidance as the necessary complement to human wisdom; Proverbs makes this explicit and monotheistic.</p>",
    "27": "<p><em>Whoever gives to the poor will not lack, and he who hides his eyes from the poor will get many a curse</em> — the giving-to-poor-guarantees-sufficiency paradox is stated multiple times in Proverbs (19:17; 21:13; 22:9). The economics rest on the belief that God manages the distribution of resources and that generosity aligns the giver with his distributive justice. The curse (<em>meerat me'od</em>, many curses) on the one who averts his eyes is the communal curse pronounced on covenant-breakers — the language draws on the Deuteronomic blessing/curse framework (Deut 27-28).</p>",
    "28": "<p><em>When the wicked rise, people hide themselves, but when they perish, the righteous increase</em> — the social-barometer verse closing chapter 28 (cf. 28:12, 29:2 for the same formula in slight variation). The demographic implication: the visibility and flourishing of the righteous is inversely correlated with wicked power. This is the wisdom tradition's political theology in compressed form — governance quality shapes whether the population can live openly and multiply. The Proverbs pattern here anticipates the prophetic vision of the restored community in which righteousness defines public space.</p>"
  },
  "29": {
    "1": "<p><em>He who is often reproved, yet stiffens his neck, will suddenly be broken beyond healing</em> — the neck-stiffening (<em>yaqsheh oref</em>) metaphor is used of oxen resisting the yoke (Deut 31:27; Jer 7:26). The cumulative-reproof-ignored pattern describes not one failure but a pattern of sustained resistance to correction — the final rupture (<em>yishaber</em>, will be broken) is the consequence of the accumulated pattern, not any single act. The <em>ein marpe</em> (no healing) formula appears also in Prov 6:15 and 29:1 — it is the wisdom tradition's way of marking irreversibility.</p>",
    "2": "<p><em>When the righteous increase, the people rejoice, but when the wicked rule, the people groan</em> — the political-barometer proverb (cf. 28:12, 28:28). The word <em>yishbor</em> at 29:2 has a variant form in the Masoretic tradition worth noting; the main thrust is clear: community affect (rejoicing/groaning) tracks directly with the moral character of those in power. ANE royal inscriptions regularly claimed that the king's just reign brought rejoicing to the population; Proverbs makes this a diagnostic rather than propaganda formula.</p>",
    "3": "<p><em>He who loves wisdom makes his father glad, but a companion of prostitutes squanders his wealth</em> — the father-son frame (recurring throughout Proverbs 1–9 and in the wisdom schools generally). The economic observation is concrete: the prostitute-companion loses his wealth. This is not merely moral condemnation but economic analysis — in ancient economies, sexual vice was often connected to the hospitality/tavern industries that extracted wealth from the young. The Ben Sira (Sirach 9:6) and Egyptian wisdom (<em>Papyrus Insinger</em>) make the same connection.</p>",
    "4": "<p><em>By justice a king establishes the land, but he who exacts gifts tears it down</em> — <em>mishpat</em> as the foundation of the royal office; <em>ish terumot</em> (a man of heave-offerings, i.e., one who extracts tribute/bribes) is the opposite of the just king. The agricultural metaphor: justice plants, bribery uproots. The Mesopotamian ideal of the king as the one who establishes equity (<em>misharum</em>) and justice (<em>kettu</em>) — articulated in the Hammurabi prologue — is the background against which Proverbs' royal ideal makes sense. The king who extracts rather than establishes is a cosmic disorder, not merely a legal infraction.</p>",
    "5": "<p><em>A man who flatters his neighbor spreads a net for his feet</em> — flattery (<em>chalaq</em>, smooth speech) as a trap is a consistent wisdom image (cf. Prov 26:28; 28:23). The net-for-feet metaphor draws on bird-trapping imagery common in Egyptian and Israelite wisdom. The flattery trap is both social (creating false obligations and dependencies) and cognitive (the flatterer eventually requires the flattered to ignore reality). ANE court texts warn officials against surrounding themselves with flatterers who prevent accurate assessment of situations.</p>",
    "6": "<p><em>An evil man is ensnared in his transgression, but a righteous man sings and rejoices</em> — the trap-of-one's-own-sin theme (cf. Prov 5:22): the transgression functions as a self-constructed snare. The contrast with the singing-and-rejoicing righteous uses the vocabulary of festival and temple worship — <em>yason vesamach</em> echoes the language of covenant celebration. The interior freedom of the righteous (who has no hidden guilt constructing its own prison) is expressed in the capacity for uninhibited worship.</p>",
    "7": "<p><em>A righteous man knows the rights of the poor; a wicked man does not understand such knowledge</em> — <em>da'at din</em> (knowledge of the cause of the poor) is the specific competence Proverbs identifies as the mark of righteousness. The wicked man's failure is cognitive (<em>lo yavin</em>, does not understand) — a deliberate epistemological closure rather than mere ignorance. ANE legal practice gave the poor access to the king's court in theory (the Hammurabi code specifically mentions defending widows and orphans); Proverbs describes the gap between theory and the discernment required to practice it.</p>",
    "8": "<p><em>Scoffers set a city aflame, but wise men turn away wrath</em> — <em>anshei lazon</em> (men of mockery/scoffing) are the wisdom tradition's persistent antagonists. The city-inflaming image is not merely metaphorical: in ancient walled cities, inflammatory speech that escalated factional conflicts could trigger riots that literally burned sections of the city. The wise men who turn away wrath (<em>yashivu af</em>) are the de-escalators — those whose measured speech cools communal tension before it ignites. This is wisdom's civic function in concentrated form.</p>",
    "9": "<p><em>If a wise man has an argument with a fool, the fool only rages and laughs, and there is no quiet</em> — the communication-gap between wisdom and folly: the fool cycles between rage and derision but cannot process the substance of argument. This observation applies to formal legal/court contexts (<em>nishpat</em>, argues/goes to court) as much as personal dispute — the fool in a legal context simply escalates rather than engaging the issue. ANE wisdom texts note similar dynamics in depicting the fool as one who cannot learn from counsel or correction.</p>",
    "10": "<p><em>Bloodthirsty men hate one who is blameless and seek the life of the upright</em> — <em>anshei damim</em> (men of blood) are the antithesis of the upright in both Psalms and Proverbs. The observation is sociological: moral character creates enmity from those whose own character is exposed by contrast. The seeking-of-the-upright's-life is the persecution dynamic that wisdom literature takes seriously as a real social phenomenon — the righteous are not automatically protected from violence by their righteousness but by divine providence.</p>",
    "11": "<p><em>A fool gives full vent to his spirit, but a wise man quietly holds it back</em> — <em>kol rucho</em> (all his spirit/wind) — the fool exhausts his entire emotional reserve in a single outburst. The wise man's restraint (<em>b'achor yeshabbechenah</em>, calms it in the back, i.e., holds it in reserve) is not suppression but management — the capacity to modulate emotional expression according to context. This is the ANE wisdom ideal of the measured official who controls his words and demeanor in court settings. Egyptian <em>Instruction of Ptahhotep</em> specifically addresses this quality as the mark of the capable official.</p>",
    "12": "<p><em>If a ruler listens to falsehood, all his officials will be wicked</em> — the systemic-corruption observation: moral tone in leadership cascades downward through institutions. The ruler who entertains (<em>maqshiv al devar shaqer</em>) false reports creates an environment where officials learn that falsehood is rewarded. ANE court texts (Egyptian, Babylonian, Assyrian administrative documents) document this dynamic — the quality of information reaching the king determined administrative integrity throughout the system. Proverbs' observation anticipates modern organizational theory about leadership culture.</p>",
    "13": "<p><em>The poor man and the oppressor meet together; the LORD gives light to the eyes of both</em> — the economic encounter between debtor/laborer and creditor/oppressor is given a theological framing: both are creatures of God who sustains their existence equally. The light-giving formula (<em>meir einei shneihem</em>) is the same as Prov 22:2 — both rich and poor are God's creatures. The paradox is that the oppressor's own life is sustained by the God whose poor he oppresses — an implicit judgment within an observation about shared creaturely dependence.</p>",
    "14": "<p><em>A king who faithfully judges the poor — his throne will be established forever</em> — the permanent-throne formula tied to just treatment of the poor is the royal theology in concentrated form. The three classic texts for the Davidic covenant (2 Sam 7; Ps 72; Ps 89) all connect the eternal throne to just governance. Psalm 72:4 is the most direct parallel: <em>may he defend the cause of the poor</em>. The justice-permanence connection is not merely conditional promise but structural — the king whose reign is built on exploiting the weak has no stable foundation; the one built on justice for the weak mirrors divine governance and therefore shares its permanence.</p>",
    "15": "<p><em>The rod and reproof give wisdom, but a child left to himself brings shame to his mother</em> — <em>shevet vetochachah</em> (rod and reproof) — both physical and verbal correction. The ANE pedagogical tradition universally endorsed corporal discipline for children; the <em>Instruction of Any</em> (Egypt) and Babylonian school texts document this. What distinguishes Proverbs is the pairing with <em>tochachah</em> (verbal reproof/rebuke) — physical correction alone is insufficient without the explanatory word that connects the discipline to the principle. The shame brought to the mother by the undisciplined child reflects the honor-culture concern for family reputation.</p>",
    "16": "<p><em>When the wicked increase, transgression increases, but the righteous will look upon their downfall</em> — the eschatological confidence embedded in the observation: however dominant wickedness becomes in the present, the righteous will outlast it and witness its collapse. This is not passive resignation but the long-term perspective wisdom cultivates — the ability to see through present appearances to eventual outcomes. The verb <em>yiru bemifaltan</em> (will see in their downfall) is the language of vindication-witness that appears in the Psalms of lament.</p>",
    "17": "<p><em>Discipline your son, and he will give you rest; he will give delight to your heart</em> — the positive parental incentive: the well-disciplined son is not merely the absence of shame but a positive source of rest (<em>menucha</em>) and delight (<em>maadanim</em>). The language of rest draws on the covenant-rest ideal (Deut 12:9-10); the delight of a well-formed child is described as the parent's experience of the fruition of their investment. This frames discipline as a long-term project with a known payoff rather than reactive management of immediate behavior.</p>",
    "18": "<p><em>Where there is no prophetic vision, the people are unrestrained; but blessed is he who keeps the law</em> — <em>chazon</em> (vision/oracle) is the technical term for prophetic revelation, used in the superscriptions of Isaiah (Isa 1:1), Nahum, and Obadiah. The <em>para</em> (unrestrained, let loose) is used of Aaron's failure at the golden calf (Exod 32:25) — letting the people run loose. The connection between prophetic word and social order: the community ordered by Torah and prophetic guidance holds together; without it, it dissolves into individual impulse. The beatitude form (<em>ve'oshrei</em>) at the verse's close ties law-keeping to blessing.</p>",
    "19": "<p><em>By mere words a servant is not disciplined, for though he understands, he will not respond</em> — the practical observation about the limits of verbal instruction alone with some people. The ancient world's servant class operated under physical power structures; verbal reproof without structural consequence had limited effect. This is not an endorsement of abuse but an observation that character formation requires more than words — consistent structural consequences are needed for some dispositions. ANE texts on household management make similar observations about the effectiveness of different corrective approaches.</p>",
    "20": "<p><em>Do you see a man who is hasty in his words? There is more hope for a fool than for him</em> — the emphatic form <em>chazita ish yaz bifdevarav</em> (do you see a man hasty in his words?) uses the instructional-observation formula. The hasty word as worse than simple folly: the fool may be reachable, but the person who rushes to speak before thinking has made impulsiveness itself a habit — a disposition more resistant to correction than mere intellectual limitation. This is wisdom's epistemology of character: habits of speech shape the soul's responsiveness to correction.</p>",
    "21": "<p><em>Whoever pampers his servant from childhood will in the end find him to be his heir</em> — the household management observation. The Hebrew is notoriously difficult; the rare word <em>manon</em> (heir/grief?) appears only here. The social observation seems to be that over-indulgent treatment of a servant from childhood disrupts the master-servant relationship structure — in ANE household economies, clear hierarchies were considered necessary for functional management. The observation reflects the wisdom tradition's interest in household order as a microcosm of social order generally.</p>",
    "22": "<p><em>A man of wrath stirs up strife, and one given to anger causes much transgression</em> — <em>ish af</em> (a man of nose, i.e., anger) and <em>baal chemah</em> (master of heat/rage) — two synonymous phrases for the habitually angry person. The causal chain is specific: anger → strife → transgression — each step escalating beyond the original irritant. This matches ANE wisdom's consistent treatment of anger as a cascade-trigger rather than an isolated event. <em>Instruction of Amenemope</em> ch.4 is devoted to the contrast between the heated man and the truly silent man — one of the most sustained ANE treatments of anger management.</p>",
    "23": "<p><em>One's pride will bring him low, but he who is lowly in spirit will obtain honor</em> — the pride-humiliation / humility-exaltation reversal is one of Proverbs' most repeated structural principles (cf. Prov 16:18; 18:12). This is the wisdom tradition's social physics: pride overextends itself and collapses; the humble person who accurately assesses his own standing is positioned for sustainable honor. In ANE court contexts, officials who overplayed their status relative to the king were systematically destroyed; wisdom literature records the pattern as a universal social observation.</p>",
    "24": "<p><em>The partner of a thief hates his own life; he hears the curse but discloses nothing</em> — <em>cholef im gannav</em> (partner with a thief) — the legal-social position. In Israelite law, the public adjuration or curse called on anyone who had witnessed a crime to come forward (Lev 5:1). The accomplice who stays silent despite the public curse incurs that curse upon himself — <em>shone'a alah</em> (hears the curse) and says nothing. The self-destructive nature of complicity is the wisdom insight: the accomplice damages himself even when the crime is another's.</p>",
    "25": "<p><em>The fear of man lays a snare, but whoever trusts in the LORD is kept safe</em> — <em>cherdath adam</em> (trembling before man) is the human approval-seeking that Proverbs identifies as the alternative to fear of the LORD. The snare-imagery: fear of human opinion is not merely uncomfortable but a trap that prevents right action. The entire wisdom project of Proverbs is aimed at replacing fear of man with fear of God as the organizing principle of life — this verse states the stakes plainly. In ANE administrative culture, the official who shaped his decisions by what would please superiors rather than what was right was considered the archetype of the unreliable counselor.</p>",
    "26": "<p><em>Many seek the face of a ruler, but it is from the LORD that a man gets justice</em> — the court-access proverb: petitioners flood the royal court seeking favorable rulings, but the ultimate source of justice is not the human official. The irony is structural: the more a society relies on court-access and patronage networks for justice, the more it misses the actual source. This is the wisdom tradition's theological critique of political systems — not a condemnation of courts but a reorientation of ultimate trust. ANE petitioner papyri document the constant pressure on officials from those seeking favorable treatment.</p>",
    "27": "<p><em>An unjust man is an abomination to the righteous, and one whose way is straight is an abomination to the wicked</em> — the mutual-abomination proverb: character incompatibility produces mutual revulsion. The <em>toevah</em> (abomination) vocabulary is used in Deuteronomy for things that violate covenant purity; here it describes the visceral incompatibility between righteousness and wickedness. This is not mere antipathy but an epistemological point: the wicked cannot accurately perceive or appreciate what is straight (upright), and the righteous cannot align themselves with injustice — the two orientations are categorically incompatible.</p>"
  },
  "30": {
    "1": "<p><em>The words of Agur son of Jakeh. The oracle. The man declares: I am weary, O God; I am weary, O God, and worn out</em> — Agur ben Jakeh is unknown outside this text; attempts to identify him with Solomon or another biblical figure have not persuaded. The superscription uses <em>massa</em> (oracle/burden) — the same term used for prophetic oracles against foreign nations (Isa 13-23; Nah 1:1). Agur may be non-Israelite: Massa was a north Arabian tribe descended from Ishmael (Gen 25:14), and the wisdom tradition in Proverbs is explicitly international (Prov 22:17-24:22 from Egypt; 30-31 possibly from Arabia). This international character of wisdom literature matches the ANE reality: wisdom schools across Egypt, Mesopotamia, and Canaan shared materials and concepts.</p>",
    "2": "<p><em>Surely I am too stupid to be a man; I have not the understanding of a man</em> — Agur's self-deprecating opening (<em>ba'ar anochi me'ish</em>, I am more brutish than a man) is a rhetorical device — the wisdom teacher who confesses ignorance sets up the reader to receive what follows as humbled insight rather than arrogant assertion. Egyptian wisdom (<em>Instruction of Amenemope</em>) and Mesopotamian wisdom texts employ similar rhetorical self-deprecation as a way of establishing the teacher's credibility precisely through the acknowledgment of limits.</p>",
    "3": "<p><em>I have not learned wisdom, nor have I knowledge of the Holy One</em> — <em>kedoshim</em> (Holy Ones) — the plural used for the divine in some OT texts (Prov 9:10; Hos 12:1). The acknowledgment of not having attained wisdom or knowledge of God is the prerequisite for the questions that follow. Agur's confession is the wisdom tradition's version of Socratic ignorance — knowing that one does not know is the beginning of genuine inquiry. This sets up the rhetorical questions of verse 4 as genuine questions rather than rhetorical flourishes masking known answers.</p>",
    "4": "<p><em>Who has ascended to heaven and come down? Who has gathered the wind in his fists? Who has wrapped up the waters in a garment? Who has established all the ends of the earth? What is his name, and what is his son's name? Surely you know!</em> — the cosmological questions and the divine name-question. The ANE background: in Mesopotamian cosmology, control over wind, water, and the cosmic boundaries was specifically divine territory. The Ugaritic texts (Baal Cycle) describe Baal's control over wind and rain as the basis of his divine status; the Babylonian <em>Enuma Elish</em> describes Marduk's establishment of the earth's limits. Agur's questions deliberately invoke these ANE cosmological motifs and direct them toward the single unnamed God of Israel. The question about the Son's name (<em>ma shemo uma shem beno</em>) is remarkable: the ANE divine-family tradition (divine sons, divine councils) is here queried for the specifically Israelite God whose Son's name is unknown. This is the OT's most direct anticipatory formulation of the Father-Son relationship in the Godhead.</p>",
    "5": "<p><em>Every word of God proves true; he is a shield to those who take refuge in him</em> — <em>kol imrat Eloah tzerufah</em> (every word/saying of God is refined/tested) uses the metallurgical image of smelted silver (cf. Ps 12:6; 18:30). The divine speech is compared to metal that has been through fire and emerged pure — not in need of testing but having already passed every test. The shield-metaphor (<em>magen hu</em>) is covenant protection language (Gen 15:1; Ps 3:3). The two images together — refined metal and protective shield — describe the divine word as both epistemically reliable and practically protective.</p>",
    "6": "<p><em>Do not add to his words, lest he rebuke you and you be found a liar</em> — the canonical-boundary warning. The prohibition on adding to God's words appears in the legal tradition (Deut 4:2; 12:32) and is implied throughout the prophetic claim to speak only what God has spoken. The wisdom version here is more personal: the person who adds to God's words will be discovered (<em>venimtzata chazav</em>, will be found a liar) — found out by God himself. The ANE scribal tradition had similar concepts of the sacred text's integrity; Egyptian wisdom texts were passed down with strong prohibitions against unauthorized addition or alteration.</p>",
    "7": "<p><em>Two things I ask of you; deny them not to me before I die</em> — the numbered-request form, introducing the famous petition of verses 8-9. The petition structure (<em>sheal sha'alti mimmeka</em>) is the prayer-formula of the Psalms. The two requests function as a wisdom teaching about the spiritual dangers of both poverty and wealth — a form of theological economics found nowhere else in the OT with this precision. Egyptian and Mesopotamian wisdom texts do address the dangers of extreme wealth, but the paired-danger formulation (poverty AND wealth as both spiritually dangerous) is distinctive to Agur's petition.</p>",
    "8": "<p><em>Remove far from me falsehood and lying; give me neither poverty nor riches; feed me with the food that is needful for me</em> — <em>lechem chukki</em> (bread of my portion/allotment) — the prescribed portion, enough and not more. The word <em>chok</em> (portion, statute, allotment) connects the prayer to the whole system of divinely ordained portions — each person has their allotment. The petition for exactly the right amount is the antithesis of both the grasping greed Proverbs consistently condemns and the resignation-to-poverty that would damage one's capacity to serve. The ANE background: Egyptian wisdom texts address the proper management of food and provision, but the theological precision of <em>lechem chukki</em> (my appointed portion) as a prayer concept is Agur's distinctive contribution.</p>",
    "9": "<p><em>Lest I be full and deny you and say, 'Who is the LORD?' or lest I be poor and steal and profane the name of my God</em> — the theological anthropology of the petition: abundance produces forgetting God; scarcity produces theft which profanes the divine name. The <em>kichashti</em> (I deny/lie) in the context of fullness echoes the Deuteronomic warning (Deut 8:11-14): when you have eaten your fill in the land, do not forget the LORD. The profaning of God's name through poverty-theft is the covenant violation of Lev 19:12 — the connection between economic desperation and desecration of the divine name is Agur's specific insight. Both forms of extremity compromise the covenant relationship.</p>",
    "10": "<p><em>Do not slander a servant to his master, lest he curse you and you be held guilty</em> — the social observation about the legal and moral risks of false accusation. In ANE law (Hammurabi code; Hittite laws), false witness against a person carried penalties proportional to the wrongful accusation. The servant who is falsely accused and curses the accuser exercises a recognized social right; the wisdom tradition here validates the curse of the unjustly accused as carrying legal and moral weight. The household servant is one of the most legally vulnerable figures in ANE society; their capacity to curse a false accuser is presented as divinely recognized.</p>",
    "11": "<p><em>There are those who curse their fathers and do not bless their mothers</em> — the first of four <em>dor</em> (generation) sayings in 30:11-14, each describing a moral type. This opening with parent-cursing violates the fifth commandment at its most fundamental level. In ANE culture, parent-cursing was a grave legal offense — the <em>Code of Hammurabi</em> specified severe penalties for children who disowned or struck parents. The four-generation catalogue that follows builds a comprehensive portrait of the type of person whose character is entirely disoriented — the parent-curser is presented as the seed of all the other failures.</p>",
    "12": "<p><em>There are those who are pure in their own eyes but are not washed of their filth</em> — the self-perception gap: the subjective experience of purity combined with objective uncleanliness. The <em>tzoa</em> (filth/excrement) is the most concrete possible image for impurity — the contrast between self-assessed cleanliness and the divine-perspective assessment of actual defilement. This is the wisdom tradition's analysis of the self-righteous: their pollution is not a matter of debate but of observable reality that only their self-assessment obscures.</p>",
    "13": "<p><em>There are those — how lofty are their eyes, how high their eyelids lift!</em> — the body-language of pride: elevated eyes as the observable indicator of arrogance. In ANE iconography, the posture of deference before superiors involved lowered eyes; elevated eyes communicated defiance of hierarchy. Proverbs' wisdom tradition is intensely attentive to embodied signals of character — the eye, the mouth, the foot, the heart — as indices of inner orientation. The lofty eye (cf. Prov 6:17 where the LORD hates <em>einayim ramot</em>, lofty eyes) is the observable surface of the pride that Proverbs repeatedly identifies as the root of social and spiritual disorder.</p>",
    "14": "<p><em>There are those whose teeth are swords, whose fangs are knives, to devour the poor from off the earth, the needy from among mankind</em> — the predatory-consumption image: the wealthy who consume the poor are described in terms of their dental apparatus. The image is extreme, drawing on the ANE beast-fable tradition where predators represent social types. The four-part catalogue (30:11-14) ends with the most socially destructive type — the ones who economically devour the vulnerable. This connects to the larger Proverbs concern with justice for the poor and anticipates the prophetic indictments of Amos and Isaiah who use similar consumption-imagery for economic exploitation.</p>",
    "15": "<p><em>The leech has two daughters: Give, Give. Three things are never satisfied; four never say, 'Enough'</em> — the <em>alukah</em> (leech) appearing only here in the OT introduces the extended <em>x/x+1</em> numerical pattern (three things / four never satisfied) that characterizes the second half of chapter 30. The numerical saying (<em>shalosh hemah / ve'arba lo tovarna hon</em>) is an ANE literary form found in Mesopotamian wisdom (the Babylonian <em>Theodicy</em>), Ugaritic poetry (the Baal Cycle uses the x/x+1 form repeatedly), and Egyptian wisdom. The form focuses attention on the final, climactic member of the series rather than providing an exhaustive list. The leech's daughters as a symbol of insatiable appetite frames all the numerical sayings that follow — each describes a form of unsatisfied hunger.</p>",
    "16": "<p><em>Sheol, the barren womb, the land never satisfied with water, and the fire that never says, 'Enough'</em> — four insatiable things: death's domain always accepting the dead; the barren womb always hungry for children; the land's perpetual thirst for rain; fire's endless consumption. These are cosmic-scale observations, not merely social ones — Sheol, fertility, rain, and fire are the categories that touch the boundary between human experience and divine sovereignty. In ANE cosmology, these were precisely the domains where the gods exercised distinctive power — Mot (death), Baal (rain/fertility), the fire-gods. Agur's numerical saying naturalizes what ANE religion mythologized.</p>",
    "17": "<p><em>The eye that mocks a father and scorns to obey a mother will be picked out by the ravens of the valley and eaten by the eagles</em> — the fifth commandment again, but now with a graphic consequence: the unburied body devoured by birds. In ANE culture, burial was essential for the soul's passage — the unburied body was the worst form of death. The ravens-picking-out-the-eye precisely inverts the parent-dishonoring eye: the eye that mocked the parent will itself be the object of violence. The image is deliberately visceral — wisdom's counterpoint to the filial piety violations catalogued in verses 11-14.</p>",
    "18": "<p><em>Three things are too wonderful for me; four I do not understand: the way of an eagle in the sky, the way of a serpent on a rock, the way of a ship on the high seas, and the way of a man with a virgin</em> — the four wonders that leave no trace. The x/x+1 form now focuses on phenomena of passage without residue — the eagle, serpent, and ship traverse their media and leave no permanent mark. The fourth and climactic member (<em>derekh gever be'almah</em>, the way of a man with a young woman) applies the same observation to human courtship and sexual union — its dynamics are similarly mysterious and unrecoverable. The ANE background: the observation about things that leave no trace appears in several wisdom contexts, but Agur's four-member catalogue with the fourth member as the human-relational mystery is distinctive.</p>",
    "19": "<p>The wonder formula here (<em>derech nesher bashamayim</em>, way of an eagle in the heavens) uses <em>derech</em> (way/path) for all four — the word that throughout Proverbs describes the moral path of human life. Agur applies it to natural phenomena to observe that the deepest patterns of movement through reality are beyond analytical reduction. This is the wisdom tradition's equivalent of the LORD's speeches from the whirlwind in Job — some things exceed human comprehension not because they are hidden but because they are genuinely beyond discursive capture. The mysteries Agur identifies are not theological secrets but observable natural patterns that resist full explanation.</p>",
    "20": "<p><em>This is the way of an adulteress: she eats and wipes her mouth and says, 'I have done no wrong'</em> — the counter-image to the four wonders. The adulteress applies the trace-leaving-no-trace pattern to moral evasion: consuming and then erasing the evidence, claiming innocence. This is not the same as the genuine wonders of verse 19 — it is the imitation of unaccountability for moral purposes. The wisdom tradition's harshest treatment of adultery (Prov 2:16-19; 5:3-14; 7:6-27) here receives a concentrated image: the self-declared innocence of the one who has systematically violated covenant fidelity.</p>",
    "21": "<p><em>Under three things the earth trembles; under four it cannot bear up</em> — the cosmic-weight formula: social disorders so severe the earth itself is disrupted. The ANE cosmological framework in which human moral disorder destabilizes the earth (cf. Isa 24:19-20; Ps 82:5 where the earth's foundations shake under unjust judgment) is here applied to specific social scenarios. The earth-trembling formula elevates what follows from social observation to cosmic significance — these are not merely bad outcomes but structural violations of the created order.</p>",
    "22": "<p><em>A servant when he reigns, and a fool when he is filled with food</em> — the first two of four earth-trembling scenarios. The slave-become-king disrupts the hierarchical order that ANE society considered divinely ordained; the fool satiated with food loses whatever corrective constraint hunger imposed. Both images describe the removal of natural limits that organized human behavior — the slave was supposed to serve, and service imposed humility; the fool without hunger had no practical reason to listen to wisdom. The social-order assumptions embedded here reflect ANE hierarchical anthropology rather than endorsing those hierarchies as ultimate goods.</p>",
    "23": "<p><em>An unloved woman when she gets a husband, and a maidservant when she displaces her mistress</em> — the third and fourth earth-trembling scenarios. The unloved woman who finally marries (<em>senuah ki tiba'al</em>) disrupts household order through the bitter fruit of long rejection; the maidservant who inherits her mistress's position inverts the servant-master structure. The Hagar-Sarah dynamic (Gen 16) is the paradigmatic example — Hagar's conception made her despise her mistress (Gen 16:4). Both scenarios describe domestic inversions with cosmic resonance — the household, as the primary social unit in ANE culture, was the microcosm of cosmic order; its inversion was genuinely disorienting at the societal level.</p>",
    "24": "<p><em>Four things on earth are small, but they are exceedingly wise: the ants, the rock badgers, the locusts, and the lizard</em> — the small-but-wise catalogue, the most pedagogically oriented of Agur's numerical sayings. The x/x+1 form here (four, though the standard formula would be three-four) lists creatures whose wisdom exceeds their size. The observation method is direct natural observation — what behaviors do small creatures exhibit that demonstrate their adaptive intelligence? This is the wisdom tradition's natural philosophy: the created order is a school, and attentive observation of small things yields large lessons.</p>",
    "25": "<p><em>The ants are a people not strong, yet they provide their food in the summer</em> — ant-industry as the model of provision without strength. The Hebrew <em>am</em> (people) applied to ants treats them as a social unit with collective purposes — the ANE wisdom tradition anthropomorphized animal behavior to extract moral lessons. Agur's use of <em>am</em> (people) for ants anticipates the more developed natural-philosophy tradition of the Hellenistic period; within the OT wisdom tradition it is distinctive. The summer-provision point parallels Prov 6:6-8 where the ant is the model for the sluggard.</p>",
    "26": "<p><em>The rock badgers are a people not mighty, yet they make their homes in the cliffs</em> — the <em>shefanim</em> (rock badgers, hyraxes) who make their homes in rocky cliffs despite lacking the strength to defend territory. The wisdom insight: lack of natural strength is compensated by intelligence about one's environment. The hyrax's ecological niche — using rock formations inaccessible to predators — is the natural-philosophy observation that wisdom literature translates into social principle: know your environment and use its features to compensate for your vulnerabilities.</p>",
    "27": "<p><em>The locusts have no king, yet all of them march in rank</em> — locust-swarms without a central commander achieving coordinated movement: self-organizing order without hierarchy. The ANE understanding of locusts was shaped by observation of their devastating swarms (cf. Joel 1-2 where locust-swarms describe the day of the LORD). Agur's observation inverts the typical fear-of-locusts: their self-organizing collective movement is a form of wisdom — coordinated purposive action without needing a central authority. This is the most countercultural of Agur's small-wise observations in an ANE context where hierarchical authority was the assumed basis of all organization.</p>",
    "28": "<p><em>The lizard you can take in your hands, yet it is in kings' palaces</em> — the gecko/lizard (<em>semamit</em>) that can be caught with the hand yet inhabits the highest social spaces. The wisdom insight is about access through adaptability: the small, accessible creature penetrates spaces closed to larger, more powerful animals. The kings' palace was the most guarded social space in ANE culture — accessible only through power or permission. The lizard achieves this access through sheer adaptive skill. The social principle: wisdom provides access that power and status cannot.</p>",
    "29": "<p><em>Three things are stately in their tread; four are stately in their stride: the lion, the strutting rooster, the he-goat, and a king whose army is with him</em> — the stately-stride catalogue. The x/x+1 form here provides three animals plus a human figure as the climactic member: the king with his army. The lion as first member echoes Prov 28:1 (the righteous bold as a lion) — the lion's gait is the model of unafraid, unhurried authority. The ANE royal iconography consistently depicted the king in procession with his army — this is the form of human authority that most closely mirrors the lion's natural authority.</p>",
    "30": "<p><em>The lion, which is mightiest among beasts and does not turn back before any</em> — the lion as the apex predator who retreats before nothing. In ANE royal contexts, the lion-hunt was the paradigmatic royal activity — the king demonstrated his fitness for rule by mastering the creature that mastered all others. Assyrian palace reliefs show lions being hunted from chariots; Egyptian pharaohs claimed lion-kills as proof of royal valor. Agur uses the lion as the natural model of composed authority — not aggressive posturing but quiet confidence that does not retreat.</p>",
    "31": "<p><em>The strutting rooster, the he-goat, and a king whose army is with him</em> — the rooster (<em>zarzir motnayim</em>, girded of loins) and he-goat as the intermediate members of the stately-stride catalogue. The he-goat as leader of the flock is used metaphorically for leadership in the prophetic literature (Jer 50:8; Zech 10:3). The king with his army as the climactic member of a natural-observation series is Agur's way of grounding human authority in the natural order — the king's dignity is not merely conventional but reflects patterns of purposive, unhurried authority observable throughout creation.</p>",
    "32": "<p><em>If you have been foolish, exalting yourself, or if you have been devising evil, put your hand on your mouth</em> — the closing instruction uses the hand-on-mouth gesture of self-silencing. In ANE contexts, the hand-on-mouth was the gesture of the supplicant before the deity, of the accused in legal proceedings, and of the one who acknowledged superior wisdom. Job covers his mouth before God (Job 40:4). The instruction is to stop speaking before the self-exaltation escalates further — silence as the beginning of wisdom after foolish self-promotion.</p>",
    "33": "<p><em>For pressing milk produces curds, pressing the nose produces blood, and pressing anger produces strife</em> — the closing triplet of cause-and-effect observations. The agricultural-physiological-social sequence: physical pressing of milk → curd (desired transformation); physical pressing of the nose → blood (undesired pain); social pressing of anger → strife (predictable escalation). The three parallel observations are linked by the single Hebrew root <em>mitz</em> (pressing/churning) — the same mechanical pressure applied in different contexts produces predictably different outcomes. This is the wisdom tradition's most compressed statement of its method: observe cause-and-effect patterns in the natural world and apply them to social behavior.</p>"
  }
}

def main():
    e = load_comm('mkt-context', 'proverbs')
    merge_comm(e, DATA)
    save_comm('mkt-context', 'proverbs', e)
    count = sum(len(v) for v in DATA.values())
    print(f'proverbs mkt-context: wrote {count} verses across ch 28-30')

if __name__ == '__main__':
    main()
